import{_ as n,o as a,c as e,af as r}from"./chunks/framework.BSym9njW.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh/01-deploy/minicpm-o/minicpm-o-model.md","filePath":"zh/01-deploy/minicpm-o/minicpm-o-model.md","lastUpdated":1782376800000}'),o={name:"zh/01-deploy/minicpm-o/minicpm-o-model.md"};function d(s,t,i,p,l,c){return a(),e("div",null,[...t[0]||(t[0]=[r(`<h2 id="minicpm-o-4-5-模型介绍" tabindex="-1">MiniCPM-o 4.5 模型介绍 <a class="header-anchor" href="#minicpm-o-4-5-模型介绍" aria-label="Permalink to &quot;MiniCPM-o 4.5 模型介绍&quot;">​</a></h2><p>本文介绍 <strong>MiniCPM-o 4.5</strong> 的全模态架构、子模型组成与 GGUF 文件清单，帮助你在开始部署前做好准备。</p><blockquote><p>前置条件：建议先完成 <a href="/hello-rocm/zh/00-environment/">ROCm 基础环境安装</a>。</p></blockquote><hr><h3 id="一、什么是-minicpm-o" tabindex="-1">一、什么是 MiniCPM-o <a class="header-anchor" href="#一、什么是-minicpm-o" aria-label="Permalink to &quot;一、什么是 MiniCPM-o&quot;">​</a></h3><p>MiniCPM-o（Omni）是面壁智能（OpenBMB）推出的端到端全模态大模型系列。4.5 版本总参数量约 <strong>9B</strong>，由以下四个骨干模块组成：</p><table tabindex="0"><thead><tr><th>骨干模块</th><th>基础模型</th></tr></thead><tbody><tr><td>LLM 语言骨干</td><td><strong>Qwen3-8B</strong></td></tr><tr><td>视觉编码器</td><td><strong>SigLIP2</strong></td></tr><tr><td>音频编码器</td><td><strong>Whisper-medium</strong></td></tr><tr><td>语音合成（TTS）</td><td><strong>CosyVoice2</strong></td></tr></tbody></table><blockquote><p>该模型采用<strong>端到端方式构建</strong>，各模态的编码器/解码器与大语言模型通过稠密特征以端到端的方式进行紧密连接，实现了更好的信息流转与控制，有助于在训练过程中充分挖掘和利用丰富的多模态知识。</p></blockquote><p>基于上述架构，MiniCPM-o 4.5 集成了以下能力：</p><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td><strong>文本对话</strong></td><td>与普通 LLM 相同，支持多轮对话和系统提示词，支持 30+ 种语言</td></tr><tr><td><strong>语音输入</strong></td><td>实时音频流编码，理解用户语音（中英双语实时语音对话）</td></tr><tr><td><strong>图像 / 视频理解</strong></td><td>支持高分辨率图片（最高 180 万像素）和高帧率视频理解（最高 10fps）</td></tr><tr><td><strong>语音输出（TTS）</strong></td><td>生成自然语音，支持音色克隆、情感控制和长语音生成（&gt;1 min）</td></tr><tr><td><strong>全双工对话</strong></td><td>同时监听麦克风 + 生成语音回复，输入流与输出流互不阻塞</td></tr><tr><td><strong>主动交互</strong></td><td>以约 1Hz 频率持续监测输入流，可根据场景理解主动发起对话</td></tr></tbody></table><p>相比同参数量的纯文本模型，MiniCPM-o 4.5 的全双工响应延迟可达到约 <strong>800ms</strong>，在端侧设备上实现了接近实时的语音交互。</p><hr><h3 id="二、模型架构" tabindex="-1">二、模型架构 <a class="header-anchor" href="#二、模型架构" aria-label="Permalink to &quot;二、模型架构&quot;">​</a></h3><p>MiniCPM-o 4.5 由多个独立模块组成，在 <code>llama.cpp-omni</code> 中以独立 GGUF 文件分别加载：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>MiniCPM-o 4.5（全模态推理）</span></span>
<span class="line"><span>├── LLM（Qwen3-8B）      MiniCPM-o-4_5-Q4_K_M.gguf         ~4.9 GB</span></span>
<span class="line"><span>├── 视觉编码器（SigLIP2）  vision/MiniCPM-o-4_5-vision-F16.gguf  ~0.9 GB</span></span>
<span class="line"><span>├── 音频编码器           audio/MiniCPM-o-4_5-audio-F16.gguf    ~1.2 GB</span></span>
<span class="line"><span>├── TTS 语言模型         tts/MiniCPM-o-4_5-tts-F16.gguf        ~0.5 GB</span></span>
<span class="line"><span>├── TTS 投影层           tts/MiniCPM-o-4_5-projector-F16.gguf  ~0.1 GB</span></span>
<span class="line"><span>└── Token-to-Wav（声码器）</span></span>
<span class="line"><span>    ├── token2wav-gguf/encoder.gguf</span></span>
<span class="line"><span>    ├── token2wav-gguf/flow_matching.gguf</span></span>
<span class="line"><span>    ├── token2wav-gguf/flow_extra.gguf</span></span>
<span class="line"><span>    ├── token2wav-gguf/hifigan2.gguf</span></span>
<span class="line"><span>    └── token2wav-gguf/prompt_cache.gguf    合计 ~0.7 GB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p><strong>全部 10 个 GGUF 文件合计约 8.3 GB</strong>（Q4_K_M 量化版本）。</p><hr><h3 id="三、可用版本与量化" tabindex="-1">三、可用版本与量化 <a class="header-anchor" href="#三、可用版本与量化" aria-label="Permalink to &quot;三、可用版本与量化&quot;">​</a></h3><p>本教程以 <strong>Q4_K_M 量化</strong>为主，该量化方案在精度和显存占用之间取得了良好平衡，适合在消费级 AMD GPU 和 APU 上运行。</p><table tabindex="0"><thead><tr><th>文件</th><th>量化</th><th>用途</th></tr></thead><tbody><tr><td><code>MiniCPM-o-4_5-Q4_K_M.gguf</code></td><td>Q4_K_M</td><td>LLM 主干（文本生成）</td></tr><tr><td><code>vision/MiniCPM-o-4_5-vision-F16.gguf</code></td><td>F16</td><td>图像理解</td></tr><tr><td><code>audio/MiniCPM-o-4_5-audio-F16.gguf</code></td><td>F16</td><td>语音输入理解</td></tr><tr><td><code>tts/MiniCPM-o-4_5-tts-F16.gguf</code></td><td>F16</td><td>语音合成（LM 部分）</td></tr><tr><td><code>tts/MiniCPM-o-4_5-projector-F16.gguf</code></td><td>F16</td><td>语音合成（投影层）</td></tr><tr><td><code>token2wav-gguf/*.gguf</code>（5 个文件）</td><td>—</td><td>声码器（音频波形生成）</td></tr></tbody></table><blockquote><p>子模型（视觉、音频、TTS）目前仅有 F16 版本，因此即使 LLM 主干做了 Q4 量化，总体显存占用仍约 8.3 GB。未来如有 Q8 / Q4 子模型版本，显存需求可进一步压缩。</p></blockquote><hr><h3 id="四、显存需求估算" tabindex="-1">四、显存需求估算 <a class="header-anchor" href="#四、显存需求估算" aria-label="Permalink to &quot;四、显存需求估算&quot;">​</a></h3><table tabindex="0"><thead><tr><th>运行模式</th><th>需要加载的模块</th><th>约 VRAM</th></tr></thead><tbody><tr><td>纯文本对话</td><td>LLM</td><td>~5 GB</td></tr><tr><td>文本 + 图像理解</td><td>LLM + 视觉编码器</td><td>~6 GB</td></tr><tr><td>文本 + 语音输入</td><td>LLM + 音频编码器</td><td>~6.5 GB</td></tr><tr><td>全模态（语音输入 + TTS 输出）</td><td>LLM + 视觉 + 音频 + TTS + Token2Wav</td><td><strong>~9 GB</strong></td></tr></tbody></table><blockquote><p><strong>注意</strong>：上述估算基于 4096 token 上下文。使用 8192 token 上下文时，KV Cache 会额外占用约 1–2 GB。</p><p>AMD Ryzen AI MAX+ 395 等 APU 的统一内存（64 GB）可全部作为 VRAM 使用，非常适合运行全部模块，并保留充足余量应对大上下文。</p></blockquote><hr><h3 id="五、对话模式说明" tabindex="-1">五、对话模式说明 <a class="header-anchor" href="#五、对话模式说明" aria-label="Permalink to &quot;五、对话模式说明&quot;">​</a></h3><p><code>llama.cpp-omni</code> 和 MiniCPM-o-Demo 支持以下 4 种对话模式：</p><table tabindex="0"><thead><tr><th>模式</th><th>输入</th><th>输出</th><th>特点</th></tr></thead><tbody><tr><td><strong>Turn-based（轮询）</strong></td><td>音频文件 / 文本</td><td>文本 + TTS</td><td>最稳定，适合验证基础功能</td></tr><tr><td><strong>Half-Duplex（半双工）</strong></td><td>实时麦克风</td><td>文本 + TTS</td><td>说完后等待，无打断</td></tr><tr><td><strong>Omni（全双工）</strong></td><td>实时麦克风 + 摄像头</td><td>实时语音流</td><td>同时听+说，有打断能力</td></tr><tr><td><strong>Audio Duplex（纯语音全双工）</strong></td><td>实时麦克风</td><td>实时语音流</td><td>同 Omni 但不用摄像头</td></tr></tbody></table><p>CLI 部署（<code>llama-omni-cli</code>）适合验证 Turn-based 模式；Web Demo 支持全部 4 种模式，且可在浏览器中通过摄像头/麦克风实时体验 Omni 全双工。</p><hr><h3 id="六、模型下载来源" tabindex="-1">六、模型下载来源 <a class="header-anchor" href="#六、模型下载来源" aria-label="Permalink to &quot;六、模型下载来源&quot;">​</a></h3><p>GGUF 文件可从 <strong>ModelScope</strong>（国内推荐，速度更快）或 <strong>Hugging Face</strong> 下载：</p><table tabindex="0"><thead><tr><th>来源</th><th>地址</th></tr></thead><tbody><tr><td>Hugging Face</td><td><a href="https://huggingface.co/OpenBMB/MiniCPM-o-4_5-gguf" target="_blank" rel="noreferrer">OpenBMB/MiniCPM-o-4_5-gguf</a></td></tr><tr><td>ModelScope</td><td><a href="https://www.modelscope.cn/models/OpenBMB/MiniCPM-o-4_5-gguf" target="_blank" rel="noreferrer">OpenBMB/MiniCPM-o-4_5-gguf</a></td></tr></tbody></table><hr><h3 id="参考资源" tabindex="-1">参考资源 <a class="header-anchor" href="#参考资源" aria-label="Permalink to &quot;参考资源&quot;">​</a></h3><ul><li><a href="https://github.com/OpenBMB/MiniCPM-o" target="_blank" rel="noreferrer">MiniCPM-o 官方仓库</a></li><li><a href="https://arxiv.org/abs/2408.01800" target="_blank" rel="noreferrer">MiniCPM-o 技术报告（arxiv）</a></li><li><a href="https://github.com/tc-mb/llama.cpp-omni" target="_blank" rel="noreferrer">llama.cpp-omni</a></li></ul><hr><blockquote><p>了解完模型架构后，接下来请前往 <a href="./llamacpp-omni-rocm7-deploy">llama.cpp-omni CLI 部署</a> 或 <a href="./webdemo-rocm7-deploy">Web Demo 全双工部署</a>。</p></blockquote>`,39)])])}const b=n(o,[["render",d]]);export{h as __pageData,b as default};
